mapper.select:
SELECT b.id, b.building_no, b.building_name, b.building_type, b.total_floors as floor_count, 0 as rooms_per_floor, NULL as room_number_format, b.location, b.manager_id as supervisor_id, NULL as supervisor_name, b.description as notes, b.status, COALESCE((SELECT COUNT(*) FROM dormitories d WHERE d.building_id = b.id AND d.deleted = 0), 0) as total_rooms, COALESCE((SELECT SUM(d.bed_capacity) FROM dormitories d WHERE d.building_id = b.id AND d.deleted = 0), 0) as total_beds, COALESCE((SELECT SUM(d.occupied_beds) FROM dormitories d WHERE d.building_id = b.id AND d.deleted = 0), 0) as occupied_beds, b.created_at, b.updated_at FROM buildings b WHERE b.deleted = 0
AND b.building_no LIKE CONCAT('%', #{request.buildingNo}, '%')
AND b.building_name LIKE CONCAT('%', #{request.buildingName}, '%')
AND b.building_type = #{request.buildingType}
AND b.status = #{request.status}
AND b.supervisor_id = #{request.supervisorId}
ORDER BY b.building_no ASC, b.created_at DESC

SELECT COUNT(*)
FROM buildings
WHERE building_no = #{buildingNo}
AND deleted = 0

    AND id != #{excludeId}
